[
  {
    "finding_id": "F1",
    "title": "Systematic Circumvention of Overtime Reporting",
    "details": "CareScheduler was systematically populated with scheduled hours rather than actual hours worked for at least 4 months, November 2025 through March 2026. Lead Charge Nurse Donna Park confirmed in interview that outgoing Nurse Manager Linda Yee instructed her to \"enter the scheduled hours\" because \"the administration needs clean numbers and we can manage the overtime informally.\" The instruction followed two FTE departures in January 2026 and persisted as the staffing gap continued.",
    "regulatory_citation": "",
    "severity": "critical"
  },
  {
    "finding_id": "F2",
    "title": "Scope of Under-Reporting",
    "details": "Systematic under-reporting affected 9 of 11 full-time Cardiac ICU nurses. Affected nurses averaged 40.7 h/week in CareScheduler versus 58.2 h/week in badge data, a 17.5 h/week average discrepancy. The two nurses with accurate records were Donna Park (RN-01, Lead Charge Nurse) and David Okafor (RN-06, Charge Nurse), the two individuals with CareScheduler data-entry responsibility. IT Security found the pattern inconsistent with random error, with probability of chance occurrence less than 1%.",
    "regulatory_citation": "",
    "severity": "critical"
  },
  {
    "finding_id": "F3",
    "title": "Patient Safety Implications",
    "details": "Badge access data and Walsh manual records establish that 3 nurses averaged 68-72 h/week: Amy Chen (RN-02) at 68.4 h/week, Tanya Williams (RN-05) at 70.3 h/week, and Jessica Martinez (RN-07) at 68.9 h/week. Angela connects this level of sustained overtime to JONA 2010 and Trinkoff et al. 2011 evidence: estimated 3-fold medication-error risk and cognitive performance equivalent to 0.08% BAC. Two informal near-miss events were documented in independent sources: medication dosage confusion on W1 Day 4 at approximately 3:15 AM after an approximately 19-hour shift, and wrong-route administration (IV vs IM) around W-2 after an approximately 14-hour shift. Neither near-miss was reported through ClinAlert, and the formal incident log shows zero near-miss medication events for Q1 2026. The finding also identifies 23 shifts with at least one nurse on duty more than 16 consecutive hours, producing unsafe staffing ratios when fatigue-related cognitive impairment is considered.",
    "regulatory_citation": "",
    "severity": "critical"
  },
  {
    "finding_id": "F4",
    "title": "Mandatory Reporting Obligation",
    "details": "The formal finding is subject to mandatory self-report to the Washington State Department of Health within 72 hours of the formal finding date. Legal Counsel Jennifer Wu has been notified and is advising on the content and format of the mandatory report. Voluntary disclosure to CMS should also be considered because of staffing-ratio implications during the affected period.",
    "regulatory_citation": "RCW 70.41.230",
    "severity": "high"
  }
]

